'use strict';

const UP_KEY = ['ArrowUp', 'Up'];
const DOWN_KEY = ['ArrowDown', 'Down'];
const NAVIGATION_KEYS = [...UP_KEY, ...DOWN_KEY];
const ESCAPE_KEY = ['Escape', 'Esc'];
const DELETE_KEY = 'Delete';
const BACKSPACE_KEY = 'Backspace';
const DELETE_KEYS = [DELETE_KEY, BACKSPACE_KEY];

exports.DELETE_KEYS = DELETE_KEYS;
exports.DOWN_KEY = DOWN_KEY;
exports.ESCAPE_KEY = ESCAPE_KEY;
exports.NAVIGATION_KEYS = NAVIGATION_KEYS;
exports.UP_KEY = UP_KEY;
